import { useState, useEffect } from "react";
import { useParams, useNavigate, Link } from "react-router-dom";
import { useAuth } from "../context/AuthContext";
import API from "../api/axios";

const EditPostPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, loading } = useAuth();

  const [title, setTitle] = useState("");
  const [body, setBody] = useState("");
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState("");
  const [error, setError] = useState("");
  const [saving, setSaving] = useState(false);
  const [fetching, setFetching] = useState(true);

  const [darkMode, setDarkMode] = useState(false);

  /* LOAD THEME */
  useEffect(() => {
    const saved = localStorage.getItem("user-theme");
    setDarkMode(saved === "dark");
  }, []);

  /* FETCH POST */
  useEffect(() => {
    const fetchPost = async () => {
      try {
        const res = await API.get(`/posts/${id}`);
        setTitle(res.data.title);
        setBody(res.data.body);
        setPreview(
          res.data.image
            ? `http://localhost:5000/uploads/${res.data.image}`
            : ""
        );
      } catch {
        setError("Failed to load post.");
      } finally {
        setFetching(false);
      }
    };

    fetchPost();
  }, [id]);

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    setError("");

    try {
      const formData = new FormData();
      formData.append("title", title);
      formData.append("body", body);
      if (image) formData.append("image", image);

      await API.put(`/posts/${id}`, formData, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      navigate(`/post/${id}`);
    } catch {
      setError("Failed to update post.");
    } finally {
      setSaving(false);
    }
  };

  /* THEME */
  const theme = {
    page: {
      maxWidth: "900px",
      margin: "20px auto",
      padding: "20px",
      color: darkMode ? "#eee" : "#000",
    },

    headerButtons: {
      display: "flex",
      gap: "10px",
      flexWrap: "wrap",
      marginBottom: "20px",
    },

    card: {
      background: darkMode ? "#1e1e1e" : "#fff",
      borderRadius: "20px",
      padding: "25px",
      boxShadow: darkMode
        ? "0 0 15px rgba(0,0,0,0.6)"
        : "0 8px 20px rgba(0,0,0,0.1)",
    },

    input: {
      width: "100%",
      padding: "12px",
      marginBottom: "12px",
      borderRadius: "12px",
      border: darkMode ? "1px solid #444" : "1px solid #ccc",
      background: darkMode ? "#2a2a2a" : "#fff",
      color: darkMode ? "#fff" : "#000",
      outline: "none",
    },

    textarea: {
      width: "100%",
      height: "150px",
      padding: "12px",
      marginBottom: "12px",
      borderRadius: "12px",
      border: darkMode ? "1px solid #444" : "1px solid #ccc",
      background: darkMode ? "#2a2a2a" : "#fff",
      color: darkMode ? "#fff" : "#000",
      resize: "none",
      outline: "none",
    },

    fileWrapper: {
      marginBottom: "12px",
    },

    fileInput: {
      display: "none",
    },

    fileLabel: {
      display: "inline-block",
      padding: "10px 15px",
      borderRadius: "25px",
      background: darkMode ? "#f7c6d9" : "#1a4120",
      color: darkMode ? "#000" : "#fff",
      cursor: "pointer",
      fontWeight: "bold",
      marginBottom: "10px",
    },

    preview: {
      width: "100%",
      borderRadius: "15px",
      marginTop: "10px",
      maxHeight: "350px",
      objectFit: "cover",
    },

    button: {
      width: "100%",
      padding: "12px",
      borderRadius: "25px",
      border: "none",
      background: saving ? "#999" : "#1a4120",
      color: "#fff",
      fontWeight: "bold",
      cursor: saving ? "not-allowed" : "pointer",
      marginTop: "10px",
    },

    backBtn: {
      padding: "10px 14px",
      borderRadius: "25px",
      textDecoration: "none",
      fontSize: "14px",
      fontWeight: "bold",
      background: "#f7c6d9",
      color: "rgb(12, 75, 52)",
      border: "1px solid rgb(12, 75, 52)",
    },

    error: {
      background: "#ff4d6d",
      color: "#fff",
      padding: "10px",
      borderRadius: "10px",
      marginBottom: "15px",
      textAlign: "center",
    },
  };

  if (loading || fetching) {
    return <div style={{ textAlign: "center", padding: "40px" }}>Loading...</div>;
  }

  if (!user) {
    return (
      <div style={{ textAlign: "center", padding: "40px", color: "red" }}>
        Unauthorized access
      </div>
    );
  }

  return (
    <div style={theme.page}>

      {/* HEADER */}
      <div style={theme.headerButtons}>
        <Link to="/" style={theme.backBtn}>⬅ Back Home</Link>
      </div>

      {/* CARD */}
      <div style={theme.card}>
        <h2 style={{ textAlign: "center", marginBottom: "20px" }}>
          ✏️ Edit Post
        </h2>

        {error && <div style={theme.error}>{error}</div>}

        <form onSubmit={handleUpdate}>

          <input
            type="text"
            placeholder="Post title"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            style={theme.input}
            required
          />

          <textarea
            placeholder="Write your post..."
            value={body}
            onChange={(e) => setBody(e.target.value)}
            style={theme.textarea}
            required
          />

          {/* FILE UPLOAD */}
          <div style={theme.fileWrapper}>
            <label htmlFor="fileUpload" style={theme.fileLabel}>
              📁 Choose Image
            </label>

            <input
              id="fileUpload"
              type="file"
              onChange={handleImageChange}
              style={theme.fileInput}
            />
          </div>

          {/* PREVIEW */}
          {preview && (
            <img src={preview} alt="preview" style={theme.preview} />
          )}

          {/* BUTTON */}
          <button type="submit" disabled={saving} style={theme.button}>
            {saving ? "Updating..." : "Update Post"}
          </button>

        </form>
      </div>
    </div>
  );
};

export default EditPostPage;
